<template><el-tag :type="type" effect="light">{{label}}</el-tag></template>
<script setup lang="ts">import { computed } from 'vue'; import type { AssetStatus, RiskLevel } from '@/types'; import { riskText, statusText } from '@/utils/format'; const props=defineProps<{value:AssetStatus|RiskLevel|string}>(); const statusType:Record<string,any>={draft:'info',parsing:'warning',compiled:'primary',reviewing:'warning',approved:'success',published:'success',rejected:'danger',deprecated:'danger',archived:'info',low:'success',medium:'warning',high:'danger',critical:'danger'}; const label=computed(()=>statusText[props.value as AssetStatus] || riskText[props.value as RiskLevel] || props.value); const type=computed(()=>statusType[props.value] || 'info');</script>
